/**
 * Simulate a background sync with upstream ERP/PIM systems.
 * In production this would enqueue a job that touches thousands of SKUs
 * and updates pricing, inventory, and availability from the source of truth.
 *
 * The caller does NOT await this — the admin page responds immediately
 * while the sync resolves asynchronously.
 */
export async function syncPendingUpdates() {
  // Simulate the latency of a real upstream sync (pricing, inventory, etc.)
  await new Promise((resolve) => setTimeout(resolve, 3000));
  console.log('[catalog-sync] Background sync with upstream completed');
}

import { unstable_cache } from 'next/cache';
import { revalidateTag } from 'next/cache';
import { getAllProducts, syncPendingUpdates } from '@/lib/db';

/** Cache tag used for all catalog data — revalidated on sync. */
const CACHE_TAG = 'products';

/**
 * Wraps the product query with Next.js data cache so repeated page loads
 * don't hit the database on every request. The cached entry is tied to the
 * "products" tag so it can be invalidated atomically across all catalog views.
 */
const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ['product-catalog'],
  { tags: [CACHE_TAG] },
);

/* ─── Types ─────────────────────────────────────────────────────────── */

interface Product {
  id: number;
  sku: string;
  name: string;
  price: number;
  stock: number;
  status: 'active' | 'out_of_stock' | 'low_stock' | 'discontinued';
  category: string;
  updatedAt: string;
}

/* ─── Helpers ────────────────────────────────────────────────────────── */

const STATUS_LABEL: Record<Product['status'], string> = {
  active: 'Active',
  out_of_stock: 'Out of stock',
  low_stock: 'Low stock',
  discontinued: 'Discontinued',
};

const STATUS_COLOR: Record<Product['status'], string> = {
  active: '#16a34a',
  out_of_stock: '#dc2626',
  low_stock: '#d97706',
  discontinued: '#6b7280',
};

function formatCurrency(amount: number): string {
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
  }).format(amount);
}

function formatTimestamp(iso: string): string {
  return new Intl.DateTimeFormat('en-US', {
    dateStyle: 'medium',
    timeStyle: 'short',
  }).format(new Date(iso));
}

/* ─── Page ──────────────────────────────────────────────────────────── */

export default async function AdminProductsPage() {
  const products = (await getCachedProducts()) satisfies Product[];

  /**
   * Inline Server Action — submitted via the regular HTML form below.
   *
   * - Triggers a background sync with the upstream ERP/PIM system.
   * - The sync is intentionally not awaited so the admin gets an immediate
   *   response and can continue working even if the product list is briefly stale.
   * - Revalidates the "products" cache tag so all catalog views pick up fresh
   *   data on their next request (eventual consistency).
   */
  async function syncCatalog() {
    'use server';

    console.log('[catalog] Sync requested — kicking off background refresh from upstream ERP/PIM');

    // Fire the sync in the background.  In production this would enqueue a job
    // that can touch thousands of SKUs (pricing, inventory, availability).
    syncPendingUpdates().catch((err) => {
      console.error('[catalog] Background sync failed:', err);
    });

    // Invalidate every cached value tagged with "products" so the next page
    // load fetches the latest data from the database.
    revalidateTag(CACHE_TAG);
  }

  return (
    <div style={{ maxWidth: 1120, margin: '0 auto', padding: '24px 16px', fontFamily: 'system-ui, -apple-system, sans-serif' }}>
      {/* ── Header ───────────────────────────────────────────── */}
      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 24 }}>
        <div>
          <h1 style={{ fontSize: 24, fontWeight: 700, margin: 0 }}>Product Catalog</h1>
          <p style={{ color: '#6b7280', margin: '4px 0 0', fontSize: 14 }}>
            {products.length} products &middot; cached under &ldquo;{CACHE_TAG}&rdquo;
          </p>
        </div>

        <form action={syncCatalog}>
          <button
            type="submit"
            style={{
              padding: '10px 20px',
              fontSize: 14,
              fontWeight: 600,
              color: '#fff',
              backgroundColor: '#2563eb',
              border: 'none',
              borderRadius: 6,
              cursor: 'pointer',
            }}
            onMouseOver={(e) => (e.currentTarget.style.backgroundColor = '#1d4ed8')}
            onMouseOut={(e) => (e.currentTarget.style.backgroundColor = '#2563eb')}
          >
            Sync latest catalog
          </button>
        </form>
      </header>

      {/* ── Table ────────────────────────────────────────────── */}
      <div style={{ overflowX: 'auto', border: '1px solid #e5e7eb', borderRadius: 8 }}>
        <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
          <thead>
            <tr style={{ backgroundColor: '#f9fafb', borderBottom: '2px solid #e5e7eb', textAlign: 'left' }}>
              <Th>SKU</Th>
              <Th>Name</Th>
              <Th>Category</Th>
              <Th style={{ textAlign: 'right' }}>Price</Th>
              <Th style={{ textAlign: 'right' }}>Stock</Th>
              <Th>Status</Th>
              <Th>Last updated</Th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr
                key={product.id}
                style={{ borderBottom: '1px solid #e5e7eb' }}
              >
                <Td>{product.sku}</Td>
                <Td style={{ fontWeight: 500 }}>{product.name}</Td>
                <Td>{product.category}</Td>
                <Td style={{ textAlign: 'right', fontVariantNumeric: 'tabular-nums' }}>
                  {formatCurrency(product.price)}
                </Td>
                <Td style={{ textAlign: 'right', fontVariantNumeric: 'tabular-nums' }}>
                  {product.stock}
                </Td>
                <Td>
                  <span
                    style={{
                      display: 'inline-block',
                      padding: '2px 8px',
                      fontSize: 12,
                      fontWeight: 600,
                      borderRadius: 999,
                      color: STATUS_COLOR[product.status],
                      backgroundColor: `${STATUS_COLOR[product.status]}1a`,
                    }}
                  >
                    {STATUS_LABEL[product.status]}
                  </span>
                </Td>
                <Td style={{ color: '#6b7280', fontSize: 13 }}>
                  {formatTimestamp(product.updatedAt)}
                </Td>
              </tr>
            ))}
          </tbody>
        </table>

        {products.length === 0 && (
          <p style={{ padding: 32, textAlign: 'center', color: '#9ca3af' }}>
            No products found.
          </p>
        )}
      </div>

      {/* ── Info banner ──────────────────────────────────────── */}
      <p style={{ marginTop: 16, fontSize: 13, color: '#6b7280', lineHeight: 1.5 }}>
        After clicking &ldquo;Sync latest catalog&rdquo; the page re-renders immediately.
        Product data is refreshed from upstream in the background; the table may show
        briefly stale information until the next page load.
      </p>
    </div>
  );
}

/* ── Inline table-cell components (keeps styles co-located) ─────────── */

function Th({
  children,
  style,
}: {
  children: React.ReactNode;
  style?: React.CSSProperties;
}) {
  return (
    <th style={{ padding: '10px 12px', fontWeight: 600, color: '#374151', ...style }}>
      {children}
    </th>
  );
}

function Td({
  children,
  style,
}: {
  children: React.ReactNode;
  style?: React.CSSProperties;
}) {
  return (
    <td style={{ padding: '10px 12px', color: '#111827', ...style }}>
      {children}
    </td>
  );
}

