67	export default async function AdminProductsPage() {
68	  const products = (await getCachedProducts()) as Product[];
69	
70	  /**
71	   * Inline Server Action — submitted via the regular HTML form below.
72	   *
73	   * - Triggers a background sync with the upstream ERP/PIM system.
74	   * - The sync is intentionally not awaited so the admin gets an immediate
75	   *   response and can continue working even if the product list is briefly stale.
76	   * - Revalidates the "products" cache tag so all catalog views pick up fresh
77	   *   data on their next request (eventual consistency).
78	   */
79	  async function syncCatalog() {
80	    'use server';
81	
82	    console.log('[catalog] Sync requested — kicking off background refresh from upstream ERP/PIM');
83	
84	    // Fire the sync in the background.  In production this would enqueue a job
85	    // that can touch thousands of SKUs (pricing, inventory, availability).
86	    syncPendingUpdates().catch((err) => {
87	      console.error('[catalog] Background sync failed:', err);
88	    });
89	
90	    // Invalidate every cached value tagged with "products" so the next page
91	    // load fetches the latest data from the database.
92	    revalidateTag(CACHE_TAG, {});
93	  }
94	
95	  return (
96	    <div style={{ maxWidth: 1120, margin: '0 auto', padding: '24px 16px', fontFamily: 'system-ui, -apple-system, sans-serif' }}>
97	      <style>{`
98	        .sync-btn { padding: 10px 20px; font-size: 14px; font-weight: 600; color: #fff; background-color: #2563eb; border: none; border-radius: 6px; cursor: pointer; }
99	        .sync-btn:hover { background-color: #1d4ed8; }
100	        .sync-btn:active { background-color: #1e40af; }
101	      `}</style>
102	      {/* ── Header ───────────────────────────────────────────── */}
103	      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 24 }}>
104	        <div>
105	          <h1 style={{ fontSize: 24, fontWeight: 700, margin: 0 }}>Product Catalog</h1>
106	          <p style={{ color: '#6b7280', margin: '4px 0 0', fontSize: 14 }}>
107	            {products.length} products &middot; cached under &ldquo;{CACHE_TAG}&rdquo;
108	          </p>
109	        </div>
110	
111	        <form action={syncCatalog}>
112	          <button type="submit" className="sync-btn">
113	            Sync latest catalog
114	          </button>
115	        </form>
116	      </header>
117	
118	      {/* ── Table ────────────────────────────────────────────── */}
119	      <div style={{ overflowX: 'auto', border: '1px solid #e5e7eb', borderRadius: 8 }}>
120	        <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 14 }}>
121	          <thead>
122	            <tr style={{ backgroundColor: '#f9fafb', borderBottom: '2px solid #e5e7eb', textAlign: 'left' }}>
123	              <Th>SKU</Th>
124	              <Th>Name</Th>
125	              <Th>Category</Th>
126	              <Th style={{ textAlign: 'right' }}>Price</Th>
127	              <Th style={{ textAlign: 'right' }}>Stock</Th>
128	              <Th>Status</Th>
129	              <Th>Last updated</Th>
130	            </tr>
131	          </thead>
132	          <tbody>
133	            {products.map((product) => (
134	              <tr
135	                key={product.id}
136	                style={{ borderBottom: '1px solid #e5e7eb' }}
137	              >
138	                <Td>{product.sku}</Td>
139	                <Td style={{ fontWeight: 500 }}>{product.name}</Td>
140	                <Td>{product.category}</Td>
141	                <Td style={{ textAlign: 'right', fontVariantNumeric: 'tabular-nums' }}>
142	                  {formatCurrency(product.price)}
143	                </Td>
144	                <Td style={{ textAlign: 'right', fontVariantNumeric: 'tabular-nums' }}>
145	                  {product.stock}
146	                </Td>
147	                <Td>
148	                  <span
149	                    style={{
150	                      display: 'inline-block',
151	                      padding: '2px 8px',
152	                      fontSize: 12,
153	                      fontWeight: 600,
154	                      borderRadius: 999,
155	                      color: STATUS_COLOR[product.status],
156	                      backgroundColor: `${STATUS_COLOR[product.status]}1a`,
157	                    }}
158	                  >
159	                    {STATUS_LABEL[product.status]}
160	                  </span>
161	                </Td>
162	                <Td style={{ color: '#6b7280', fontSize: 13 }}>
163	                  {formatTimestamp(product.updatedAt)}
164	                </Td>
165	              </tr>
166	            ))}
167	          </tbody>
168	        </table>
169	
170	        {products.length === 0 && (
171	          <p style={{ padding: 32, textAlign: 'center', color: '#9ca3af' }}>
172	            No products found.
173	          </p>
174	        )}
175	      </div>
176	
177	      {/* ── Info banner ──────────────────────────────────────── */}
178	      <p style={{ marginTop: 16, fontSize: 13, color: '#6b7280', lineHeight: 1.5 }}>
179	        After clicking &ldquo;Sync latest catalog&rdquo; the page re-renders immediately.
180	        Product data is refreshed from upstream in the background; the table may show
181	        briefly stale information until the next page load.
182	      </p>
183	    </div>
184	  );
185	}
