187	/* ── Inline table-cell components (keeps styles co-located) ─────────── */
188	
189	function Th({
190	  children,
191	  style,
192	}: {
193	  children: React.ReactNode;
194	  style?: React.CSSProperties;
195	}) {
196	  return (
197	    <th style={{ padding: '10px 12px', fontWeight: 600, color: '#374151', ...style }}>
198	      {children}
199	    </th>
200	  );
201	}
202	
203	function Td({
204	  children,
205	  style,
206	}: {
207	  children: React.ReactNode;
208	  style?: React.CSSProperties;
209	}) {
210	  return (
211	    <td style={{ padding: '10px 12px', color: '#111827', ...style }}>
212	      {children}
213	    </td>
214	  );
215	}
